advInfof () {
    local FORMAT="%s %s %s $1"
    shift

    printf "${FORMAT}" "["$($ADV_SYS_TIME_STRING)"]" "[INFO]" "$@"

    local CONTENT=$(printf "${FORMAT}" "["$($ADV_SYS_TIME_STRING)"]" "[INFO]" "$@" | sed "s/\x1B\[[0-9;]*[mK]//g")
