}

advCheckParam() {
    local TYPE="$1"
    local NAME="$2"
    shift 2

    [[ $TYPE = "unknown" ]] && advError "Unknown parameter: $NAME" && exit 1
    
    local VALUE="$@"
    [[ -z $VALUE ]] && advError "Missing $NAME" && exit 1

    case $TYPE in
        "any")
            PATTERN='.*'
            ;;
        "digit")
            PATTERN='^[0-9]$'
            ;;
        "number")
            PATTERN='^[0-9]+$'
            ;;
        "nlist")
            PATTERN='^[0-9,\-]+$'
            ;;
        nrange-*)
            PATTERN='^[0-9]+$'
            ;;
        "hex")
            PATTERN='^[0-9A-Fa-f]+$'
            ;;
        "float")
            PATTERN='^([0-9]+\.[0-9]+|[0-9]+)$'
            ;;
        "pcie")
            PATTERN='^[0-9A-Fa-f]+:[0-9A-Fa-f]+\.[0-9A-Fa-f]$'
            ;;
        "ip")
            PATTERN='^[0-9]{1,3}\.[0-9]{1,3}\.[0-9]{1,3}\.[0-9]{1,3}$'
            ;;
        *)
            PATTERN="$TYPE"
            ;;
    esac
    if [[ ! "$VALUE" =~ $PATTERN ]]; then
        advError "Invalid $NAME: $VALUE"
        exit 1
    fi
    if [[ "$TYPE" =~ ^nrange-.* ]]; then
        local RANGE_S=`echo "$TYPE" | cut -d '-' -f 2`
        local RANGE_E=`echo "$TYPE" | cut -d '-' -f 3`
        [[ $VALUE -lt $RANGE_S || $VALUE -gt $RANGE_E ]] && advError "Invalid $NAME ($RANGE_S-$RANGE_E): $VALUE" && exit 1
    fi
}

advGetNetPCIEs() {
    local NET_PCIES="`ls -l /sys/class/net/ | grep -oE '/[0-9A-Fa-f:.]+/net' | cut -d '/' -f 2 | sort`"
    [[ -z $1 ]] && echo "$NET_PCIES" && return 0
    echo "$NET_PCIES" | grep "$1:"
    return $?
}

advTrap() {
    local CALLBACK="$1"; shift
    [[ $# -eq 0 ]] && ADV_SIGS=(SIGINT SIGTERM SIGHUP) || ADV_SIGS=($@)
    for sig in ${ADV_SIGS[@]}; do
        trap "advTrapCallback $sig $CALLBACK" "$sig"
    done
}

advNoTrap() {
    [[ $# -ne 0 ]] && ADV_SIGS=($@)
    [[ -z $ADV_SIGS ]] && ADV_SIGS=(SIGINT SIGTERM SIGHUP)
    trap - ${ADV_SIGS[@]}
    unset ADV_SIGS
}

advTrapCallback() {
    advNotice "Cancelling by $1 ..."
    shift
    $@
}
